# Animated Shader Hero

WebGL2 GLSL fragment shader hero with a custom WebGLRenderer class, pointer-tracking interaction, and fractal noise cloud animation. The shader runs a fbm/clouds algorithm producing shifting ambient fire-cloud visuals. Hero content overlays the canvas with staggered CSS entrance animations.

## Use when
- Building a dark, immersive landing page hero that showcases WebGL visual depth.
- Creating a first-load reveal with GPU-rendered background motion.
- Establishing a serious, cutting-edge brand personality with custom shaders.
- Showcasing a product with a fullscreen animated ambient background.

## Stack
- Framework: react
- Libraries: none
- Requires: tailwind

## Install
```bash
none
```

## Component — animated-shader-hero.tsx
```tsx
import React, { useRef, useEffect, useState } from 'react';

// Types for component props
interface HeroProps {
  trustBadge?: {
    text: string;
    icons?: string[];
  };
  headline: {
    line1: string;
    line2: string;
  };
  subtitle: string;
  buttons?: {
    primary?: {
      text: string;
      onClick?: () => void;
    };
    secondary?: {
      text: string;
      onClick?: () => void;
    };
  };
  className?: string;
}

// Reusable Shader Background Hook
const useShaderBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  // [Full WebGLRenderer and PointerHandler class implementations]
  // [useEffect with resize, loop, setup, init]
  return canvasRef;
};

const defaultShaderSource = `#version 300 es
precision highp float;
out vec4 O;
uniform vec2 resolution;
uniform float time;
#define FC gl_FragCoord.xy
#define T time
#define R resolution
#define MN min(R.x,R.y)
float rnd(vec2 p) {
  p=fract(p*vec2(12.9898,78.233));
  p+=dot(p,p+34.56);
  return fract(p.x*p.y);
}
float noise(in vec2 p) {
  vec2 i=floor(p), f=fract(p), u=f*f*(3.-2.*f);
  float a=rnd(i), b=rnd(i+vec2(1,0)), c=rnd(i+vec2(0,1)), d=rnd(i+1.);
  return mix(mix(a,b,u.x),mix(c,d,u.x),u.y);
}
float fbm(vec2 p) {
  float t=.0, a=1.; mat2 m=mat2(1.,-.5,.2,1.2);
  for (int i=0; i<5; i++) { t+=a*noise(p); p*=2.*m; a*=.5; }
  return t;
}
float clouds(vec2 p) {
  float d=1., t=.0;
  for (float i=.0; i<3.; i++) {
    float a=d*fbm(i*10.+p.x*.2+.2*(1.+i)*p.y+d+i*i+p);
    t=mix(t,d,a); d=a; p*=2./(i+1.);
  }
  return t;
}
void main(void) {
  vec2 uv=(FC-.5*R)/MN,st=uv*vec2(2,1);
  vec3 col=vec3(0);
  float bg=clouds(vec2(st.x+T*.5,-st.y));
  uv*=1.-.3*(sin(T*.2)*.5+.5);
  for (float i=1.; i<12.; i++) {
    uv+=.1*cos(i*vec2(.1+.01*i, .8)+i*i+T*.5+.1*uv.x);
    vec2 p=uv;
    float d=length(p);
    col+=.00125/d*(cos(sin(i)*vec3(1,2,3))+1.);
    float b=noise(i+p+bg*1.731);
    col+=.002*b/length(max(p,vec2(b*p.x*.02,p.y)));
    col=mix(col,vec3(bg*.25,bg*.137,bg*.05),d);
  }
  O=vec4(col,1);
}`;

export default Hero;
```

## Demo
```tsx
import Hero from "@/components/ui/animated-shader-hero";

const HeroDemo: React.FC = () => {
  return (
    <div className="w-full">
      <Hero
        trustBadge={{
          text: "Trusted by forward-thinking teams.",
          icons: ["✨"]
        }}
        headline={{
          line1: "Launch Your",
          line2: "Workflow Into Orbit"
        }}
        subtitle="Supercharge productivity with AI-powered automation and integrations built for the next generation of teams."
        buttons={{
          primary: { text: "Get Started for Free" },
          secondary: { text: "Explore Features" }
        }}
      />
    </div>
  );
};

export default HeroDemo;
```

## Notes
- Uses WebGL2 (`getContext('webgl2')`) — falls back silently on unsupported browsers. Test in a WebGL2-capable browser.
- Uses `<style jsx>` for CSS keyframe animations (`.animate-fade-in-down`, `.animate-fade-in-up`, etc.) — requires Next.js with styled-jsx OR replace with Tailwind custom animations or a global CSS file.
- The shader source is the `defaultShaderSource` string constant defined at module level — it is a GLSL 300 es fragment shader.
